mapper.select:
SELECT MANUFACTURER AS manufacturer, EQUIPTYPE AS equipType, NAMECODE AS nameCode, ALARMMSG AS alarmMsg, NORMALIZEDALARM AS normalizedAlarm , ALARM_TYPE AS alarmType FROM RCA.AL_ALARM_NORMALIZER WHERE 1=1 AND ALARMMSG = #{alarmMsg}
AND EQUIPTYPE = #{equipType}
AND NAMECODE = #{nameCode}
AND CASE WHEN UNIT IS NOT NULL THEN #{unit} LIKE '%'||UNIT||'%' ELSE 1=1 END
ORDER BY EQUIPTYPE LIMIT 1
